{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class AnnotationRuleTypeArgumentTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Test
    fun `Issue 1756 - A type with multiple annotations inside a TypeArgumentList is not formatted correctly`() {
        val code =
            """
            data class FooRequestDto(
                val data: List<@Valid @NotNull FooDto>,
            )
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 1756 - Multiple annotations on a type argument should not be wrapped to separate lines if they fit on one line`() {
        val code =
            """
            val simpleList: List<@Foo @Bar SimpleDto>
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }
}
